// Initialize file database if not existing
function readDB() {
  try {
    if (fs.existsSync(DB_FILE)) {
      const raw = fs.readFileSync(DB_FILE, "utf-8");
      return JSON.parse(raw);
    }
  } catch (error) {
    console.error("Error reading database file, using fallback:", error);
  }
  return DEFAULT_BOARD;
}

function writeDB(data: any) {
  try {
    fs.writeFileSync(DB_FILE, JSON.stringify(data, null, 2), "utf-8");
  } catch (error) {
    console.error("Error writing database file:", error);
  }
}

// Ensure database is initialized
if (!fs.existsSync(DB_FILE)) {
  writeDB(DEFAULT_BOARD);
}

// API Routes

// 1. Get Board State
app.get("/api/board", (req, res) => {
  const data = readDB();
  res.json(data);
});

// 2. Save Board State
app.post("/api/board", (req, res) => {
  const updatedData = req.body;
  if (!updatedData || !updatedData.columns || !updatedData.tasks) {
    return res.status(400).json({ error: "Dữ liệu bảng không hợp lệ." });
  }
  writeDB(updatedData);
  res.json({ success: true, message: "Đã lưu bảng thành công." });
});

// 3. Fallback AI generator simulation (when API key is absent)
const fallbackClassify = (title: string, desc: string) => {
  const lowerTitle = (title + " " + desc).toLowerCase();
  let category = "Frontend";
  let priority = "medium";
  
  if (lowerTitle.includes("design") || lowerTitle.includes("thiết kế") || lowerTitle.includes("giao diện") || lowerTitle.includes("figma") || lowerTitle.includes("ui") || lowerTitle.includes("ux")) {
    category = "Design";
  } else if (lowerTitle.includes("api") || lowerTitle.includes("database") || lowerTitle.includes("sql") || lowerTitle.includes("server") || lowerTitle.includes("backend") || lowerTitle.includes("cơ sở dữ liệu")) {
    category = "Backend";
  } else if (lowerTitle.includes("marketing") || lowerTitle.includes("sale") || lowerTitle.includes("quảng cáo") || lowerTitle.includes("khách hàng")) {
    category = "Marketing";
  } else if (lowerTitle.includes("test") || lowerTitle.includes("kiểm thử") || lowerTitle.includes("bug") || lowerTitle.includes("lỗi")) {
    category = "Testing";
  }

  if (lowerTitle.includes("gấp") || lowerTitle.includes("khan cấp") || lowerTitle.includes("ngay") || lowerTitle.includes("quan trọng") || lowerTitle.includes("critical") || lowerTitle.includes("high")) {
    priority = "high";
  } else if (lowerTitle.includes("thong thả") || lowerTitle.includes("rảnh") || lowerTitle.includes("low") || lowerTitle.includes("nhẹ")) {
    priority = "low";
  }

  return {
    category,
    priority,
    reason: `Phân loại tự động (Dựa trên từ khóa có trong tiêu đề/mô tả). Thêm khóa API Gemini trong cài đặt để dùng mô hình AI thật.`
  };
};

const fallbackDecompose = (title: string) => {
  return [
    { text: `Tìm hiểu các yêu cầu cụ thể liên quan đến "${title}"` },
    { text: `Phác thảo giải pháp và phân tách các phần cấu phần chính` },
    { text: `Tiến hành triển khai thực tế công việc` },
    { text: `Kiểm tra chất lượng và xem xét lại kết quả hoàn thành` }
  ];
};

// 4. AI Endpoint - Auto Classify Task
app.post("/api/ai/classify", async (req, res) => {
  const { title, description } = req.body;
  if (!title) {
    return res.status(400).json({ error: "Yêu cầu tiêu đề task." });
  }

  const ai = getGeminiClient();
  if (!ai) {
    const backup = fallbackClassify(title, description || "");
    return res.json(backup);
  }

  try {
    const prompt = `Phân loại công việc (Kanban Task) sau đây:
Tiêu đề: "${title}"
Mô tả: "${description || 'Không có mô tả'}"

Hãy trả về định dạng JSON với các thông tin sau:
1. category: Gợi ý nhãn phù hợp nhất (ví dụ: "Frontend", "Backend", "Design", "Marketing", "Testing", "DevOps", "Database" hoặc một nhãn chuyên môn ngắn gọn bằng Tiếng Anh 1-2 từ, viết hoa chữ cái đầu).
2. priority: Độ ưu tiên phù hợp nhất dựa trên tính chất công việc ("low", "medium", "high").
3. reason: Một câu ngắn gọn giải thích lý do gợi ý nhãn này (bằng Tiếng Việt).`;

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            category: { type: Type.STRING, description: "Phân loại tags" },
            priority: { type: Type.STRING, description: "low, medium, high" },
            reason: { type: Type.STRING, description: "Giải thích bằng Tiếng Việt" }
          },
          required: ["category", "priority", "reason"]
        }
      }
    });

    const result = JSON.parse(response.text?.trim() || "{}");
    res.json(result);
  } catch (error: any) {
    console.error("Gemini Classify Error:", error);
    res.json(fallbackClassify(title, description || ""));
  }
});

// 5. AI Endpoint - Task Decomposer (Break task down to subtasks)
app.post("/api/ai/decompose", async (req, res) => {
  const { title, description } = req.body;
  if (!title) {
    return res.status(400).json({ error: "Tiêu đề công việc là bắt buộc." });
  }

  const ai = getGeminiClient();
  if (!ai) {
    return res.json({ subtasks: fallbackDecompose(title) });
  }

  try {
    const prompt = `Hãy đóng vai trò là một quản lý dự án chuyên nghiệp và phân tách công việc lớn sau đây thành 4 đến 6 đầu việc nhỏ/subtasks hành động được ngay:
Công việc lớn: "${title}"
Mô tả chi tiết: "${description || 'Không có mô tả'}"

Hãy trả về một danh sách JSON mẫu có cấu trúc như sau:
{
  "subtasks": [
    { "text": "Hành động cụ thể 1" },
    { "text": "Hành động cụ thể 2" }
  ]
}
Yêu cầu: Nội dung hành động viết rõ ràng, dễ hiểu, bằng Tiếng Việt, mỗi đầu việc khoảng 5-15 từ.`;

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            subtasks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING }
                },
                required: ["text"]
              }
            }
          },
          required: ["subtasks"]
        }
      }
    });

    const result = JSON.parse(response.text?.trim() || '{"subtasks": []}');
    res.json(result);
  } catch (error: any) {
    console.error("Gemini Decompose Error:", error);
    res.json({ subtasks: fallbackDecompose(title) });
  }
});

// 6. AI Endpoint - Progress Summary
app.post("/api/ai/summarize", async (req, res) => {
  const { columns, tasks } = req.body;
  if (!columns || !tasks) {
    return res.status(400).json({ error: "Yêu cầu đầy đủ dữ liệu cấu trúc bảng." });
  }

  const ai = getGeminiClient();
  const summaryPrompt = `Dưới đây là thống kê hiện tại của bảng Kanban công việc:
Danh sách cột: ${JSON.stringify(columns)}
Danh sách các task hiện có: ${JSON.stringify(tasks.map((t: any) => ({
    title: t.title,
    columnId: t.columnId,
    priority: t.priority,
    category: t.category,
    subtasks_total: t.subtasks?.length || 0,
    subtasks_done: t.subtasks?.filter((s: any) => s.completed).length || 0
  })))}

Hãy viết một báo cáo tóm tắt tiến độ cực kỳ chuyên nghiệp và truyền cảm hứng bằng Tiếng Việt dưới định dạng Markdown:
Giọng văn: Trực quan, tích cực, sáng rõ, tập trung vào giải quyết vấn đề.
Bao gồm:
1. Tổng quan ngắn gọn (Ví dụ: Số việc hoàn thành, tỉ lệ hoàn thành chung).
2. Phân tích các nút thắt cổ chai tiềm ẩn (Có task nào quan trọng bị trì trệ không? Có quá nhiều việc ở Đang làm / Review không?).
3. Gợi ý hành động tiếp theo cụ thể cho đội ngũ phát triển.
Hãy dùng định dạng Markdown đẹp, dùng bullet points rõ ràng. Không nói quá dài dòng.`;

  if (!ai) {
    // Generate a beautiful simulated response
    const total = tasks.length;
    const completedCount = tasks.filter((t: any) => t.columnId === "done").length;
    const doingCount = tasks.filter((t: any) => t.columnId === "in_progress").length;
    const rate = total > 0 ? Math.round((completedCount / total) * 100) : 0;
    
    const fallbackText = `### 📊 Báo cáo Tiến độ Dự án (Bản giả lập)

Chào bạn, đây là tóm tắt nhanh tiến trình công việc từ Trợ lý ảo do chưa kích hoạt kết nối API Gemini:

*   **Tổng số công việc:** **${total} tasks**
*   **Hoàn thành:** **${completedCount}** (${rate}%)
*   **Đang xử lý:** **${doingCount}** tasks đang tích cực thực hiện.

#### 🔍 Điểm nghẽn tiêu biểu:
*   Phát hiện có **${tasks.filter((t: any) => t.priority === 'high' && t.columnId !== 'done').length} công việc ưu tiên cao (High Priority)** vẫn chưa được hoàn thành. Đội ngũ nên lưu ý giải phóng các task này trước.

#### 💡 Đề xuất hành động:
1.  **Đẩy nhanh tiến độ các công việc trong cột Đang Làm** để nhanh chóng kiểm thử và đóng gói.
2.  **Chia nhỏ các task lớn** có chứa nhiều subtasks chưa tích hoàn thành để phân phối cho các thành viên tốt hơn.

*Kích hoạt API Key ở góc màn hình (Settings -> Secrets) để nhận phân tích chuyên sâu chi tiết từ Gemini AI thật!*`;
    return res.json({ summary: fallbackText });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: summaryPrompt
    });
    res.json({ summary: response.text });
  } catch (error) {
    console.error("Gemini summary error:", error);
    res.status(500).json({ error: "Lỗi tạo dự án tóm tắt từ Gemini." });
  }
});

// 7. AI Endpoint - Conversational Chatbot
app.post("/api/ai/chat", async (req, res) => {
  const { message, history, board } = req.body;
  if (!message) {
    return res.status(400).json({ error: "Yêu cầu lời nhắn từ người dùng." });
  }

  const ai = getGeminiClient();

  // Create clean board overview for context
  const textContext = board ? `Bảng Kanban hiện tại mang tên: "${board.title || 'Dự án'}"
Các cột: ${board.columns?.map((c: any) => `${c.id} (${c.title})`).join(", ")}
Các task hiện tại:
${board.tasks?.map((t: any) => `- [Cột ${t.columnId}] Title: "${t.title}", Tag: ${t.category}, Priority: ${t.priority}, Có ${t.subtasks?.length || 0} subtasks`).join("\n")}` : "Không có thông tin bảng";

  const systemInstruction = `Bạn là Trợ lý Dự án AI thông minh tích hợp trực tiếp trong Kanban Board (ứng dụng giống Trello).
Dưới đây là ngữ cảnh thực tế của dự án của người dùng:
${textContext}

Nhiệm vụ của bạn:
1. Trả lời người dùng một cách thân thiện, nhiệt tình bằng Tiếng Việt.
2. Trợ giúp người dùng lập kế hoạch, phân loại hoặc tóm tắt tiến trình.
3. Khi người dùng nói muốn tạo công việc mới (ví dụ: "thêm task học React", "tạo thẻ việc Thiết kế Database ở cột Cần làm"), hoặc phân rã task cụ thể, bạn cần trả lời bằng văn bản kèm đề xuất một Thao Tác Nhanh (Action Payload) dạng JSON để ứng dụng tự động thực hiện trên UI!

Phản hồi của bạn PHẢI LUÔN LÀ một đối tượng JSON có cấu trúc như sau:
{
  "text": "Lời thoại trả lời của bạn, viết bằng Markdown Tiếng Việt thật thân thiện, chuyên nghiệp.",
  "suggestedActions": [
    {
      "label": "Tên nút bấm hiển thị ngắn gọn (ví dụ: '➕ Thêm việc và Phân loại')",
      "action": "CREATE_TASK" hoặc "DECOMPOSE" hoặc "SUMMARIZE",
      "payload": {
        // Nếu action là CREATE_TASK:
        "title": "Tiêu đề công việc",
        "description": "Mô tả nếu có",
        "category": "Nhãn công việc",
        "priority": "low" hoặc "medium" hoặc "high",
        "columnId": "todo" hoặc "in_progress" hoặc "review" hoặc "done" (tìm cột phù hợp nhất)
        
        // Nếu action là DECOMPOSE:
        "taskId": "id của task nếu người dùng nhắc đến một task cụ thể hoặc tiêu đề task"
      }
    }
  ]
}
Lưu ý: Nếu không cần thực hiện hành động tự động gì đặc biệt, hãy để "suggestedActions" là một mảng rỗng [] hoặc chứa nút 'Tóm tắt tiến trình' (action "SUMMARIZE"). Không bịa tên id của task nếu không chắc chắn.`;

  if (!ai) {
    // Simulated smart response
    let replyText = `Tôi đã nhận được câu hỏi: "${message}". Để trợ giúp bạn quản lý board tốt nhất, vui lòng cấu hình API Key của bạn trong bảng **Secrets**. \n\nTuy nhiên, dựa trên nội dung bạn gửi, đây là tư duy gợi ý cho bạn: Bạn có thể thêm task và phân loại chúng vào các cột tương ứng, tập trung giải quyết các thẻ có độ ưu tiên **High** trước tiên!`;
    const actions: any[] = [];

    // Simple pattern matching for mock interactions to make it feel super alive!
    const msgLower = message.toLowerCase();
    if (msgLower.includes("thêm") || msgLower.includes("tạo") || msgLower.includes("create") || msgLower.includes("add")) {
      const detectedTitle = message.replace(/(thêm|tạo|task|công việc|thẻ|thẻ việc|ở cột|cột|vào cột)/gi, "").trim();
      const taskTitle = detectedTitle ? (detectedTitle.charAt(0).toUpperCase() + detectedTitle.slice(1)) : "Công việc mới từ Chatbot";
      replyText = `Tôi cảm thấy bạn muốn thêm một công việc mới: **"${taskTitle}"**. Tôi đã chuẩn bị một nút thao tác nhanh ở bên dưới, bạn chỉ cần một lượt nhấp chuột để tự động đưa công việc này vào cột **Cần làm** và phân loại nó ngay lập tức!`;
      actions.push({
        label: `➕ Thêm nhanh task "${taskTitle.slice(0, 20)}..."`,
        action: "CREATE_TASK",
        payload: {
          title: taskTitle,
          description: "Được khởi tạo nhanh từ đề xuất chatbot AI",
          category: msgLower.includes("thiết kế") || msgLower.includes("giao diện") ? "Design" : "Frontend",
          priority: "medium",
          columnId: "todo"
        }
      });
    } else {
      actions.push({
        label: "📊 Tóm tắt tiến độ dự án ngay",
        action: "SUMMARIZE",
        payload: {}
      });
    }

    return res.json({ text: replyText, suggestedActions: actions });
  }

  try {
    // Map existing history to Gemini API format
    const formattedHistory = (history || []).slice(-10).map((h: any) => ({
      role: h.sender === 'user' ? 'user' : 'model',
      parts: [{ text: h.text }]
    }));

    // Add current message as query
    const contents = [...formattedHistory, { role: 'user', parts: [{ text: message }] }];

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: contents as any,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json"
      }
    });

    const parsed = JSON.parse(response.text?.trim() || "{}");
    res.json(parsed);
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    res.json({
      text: "Xin lỗi, đã xảy ra một lỗi nhỏ khi kết nối với máy chủ AI. Tuy nhiên, tôi vẫn sẵn sàng đồng hành cùng bạn quản lý các thẻ công việc này!",
      suggestedActions: []
    });
  }
});


// Serve React app static files & Vite configuration
async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running at http://localhost:${PORT}`);
  });
}

startServer();
